#define _GNU_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include "sda_generated_tables.h"
#include "sda_sampler.h"
#include "sda_cycles.h"
static int cmpd(const void*a,const void*b){double x=*(const double*)a,y=*(const double*)b; return (x>y)-(x<y);} 
static void bench_one(const sda_table*t,const char*kind){ const int reps=11, samples=200000, warm=1000; double vals[11]; uint64_t overhead=sda_cycles_measure_overhead(); volatile long sink=0; sda_rng_stats total={0}; for(int r=0;r<reps;r++){ sda_bench_rng rng; sda_bench_rng_init(&rng,1234+r); sda_rng_stats st={0}; int x=0; for(int i=0;i<warm;i++) sda_sample_symmetric(t,sda_bench_random_bytes,&rng,&st,1,&x); uint64_t a=sda_cycles_start(); for(int i=0;i<samples;i++){ sda_sample_symmetric(t,sda_bench_random_bytes,&rng,&st,1,&x); sink+=x; } uint64_t b=sda_cycles_stop(); uint64_t cyc=(b>a)?b-a:0; vals[r]=(double)(cyc>overhead?cyc-overhead:cyc)/(double)samples; total.accepted_samples+=st.accepted_samples; total.attempts+=st.attempts; total.rejected_candidates+=st.rejected_candidates; total.raw_random_bits+=st.raw_random_bits; total.accepted_random_bits+=st.accepted_random_bits; }
 qsort(vals,reps,sizeof(double),cmpd); double med=vals[reps/2], p10=vals[1], p90=vals[9], min=vals[0], max=vals[10]; double dev[11]; for(int i=0;i<reps;i++) dev[i]=fabs(vals[i]-med); qsort(dev,reps,sizeof(double),cmpd); char q[64]; sda_print_u128(t->denominator,q,sizeof q); double attempts=(double)total.attempts/(double)total.accepted_samples; double accbits=(double)t->denominator_bits; double rawbits=(double)((unsigned long long)total.raw_random_bits)/(double)total.accepted_samples; FILE*csv=fopen("generated/sda_cycle_benchmark.csv","a"); if(csv){fprintf(csv,"%s,%s,%.6f\n",t->parameter_set,kind,med); fclose(csv);} printf("%s,%s,q=%s,q_bits=%d,entries=%zu,fixed_packed_bits=%zu,native_cumulative_bytes=%zu,median_cycles=%.2f,MAD=%.2f,p10=%.2f,p90=%.2f,min=%.2f,max=%.2f,attempts=%.4f,accepted_bits=%.2f,measured_raw_bits=%.2f,sink=%ld\n",t->parameter_set,kind,q,t->denominator_bits,t->table_length,t->ideal_packed_bits,t->table_length*sizeof(sda_u128),med,dev[reps/2],p10,p90,min,max,attempts,accbits,rawbits,(long)sink); }
int main(int argc,char**argv){(void)argc;(void)argv; sda_cycles_pin_to_cpu(0); printf("cycle_benchmark,timer=%s,serialization=CPUID/RDTSC...RDTSCP/CPUID,cpu=%s,overhead=%llu\n",sda_cycles_supported()?"x86-tsc":"clock-fallback",sda_cycles_cpu_model(),(unsigned long long)sda_cycles_measure_overhead()); FILE*csv=fopen("generated/sda_cycle_benchmark.csv","w"); if(csv){fprintf(csv,"parameter_set,sampler_type,median_cycles_per_sample\n"); fclose(csv);} for(size_t i=0;i<sda_generated_tables_count;i++){ bench_one(&sda_generated_tables[i],"sda-cdt"); printf("%s,classical-cdt,status=unavailable,speedup unavailable\n",sda_generated_tables[i].parameter_set); } return 0; }
